scwin.f_grdHeiht = function(objGrdId, size) {
    let objGrd = $p.getComponentById(objGrdId);
    if (objGrd) {
        let strHeight = objGrd.getStyle("height");
        let intHeight = parseInt(strHeight.replace("px", ""));
        intHeight = intHeight + size;
        if (intHeight > 0) {
            objGrd.setStyle("height", intHeight + "px");
        }
    }
};

scwin.f_getTime = function() {
    scwin.currDate = new Date();
    scwin.currTime = scwin.leadingZeros(scwin.currDate.getHours(), 2) + scwin.leadingZeros(scwin.currDate.getMinutes(), 2);
};

scwin.leadingZeros = function(n, digits) {
    let zero = '';
    n = n.toString();
    if (n.length < digits) {
        for (let i = 0; i < digits - n.length; i++) {
            zero += '0';
        }
    }
    return zero + n;
};

