scwin.sbm_RetrieveBlk_submitdone = function(e) {
    let rowCnt = ds_fl.getRowCount();
    scwin.iCargoCnt = 0;

    let row = 0;
    if (rowCnt < 1) return;
    scwin.selectedLclRow = "0";

    if (scwin.vehclType == "mb") {
        scwin.selectedvehclRow = "";
        scwin.ez110Idx = "";
    }

    scwin.showmb(ds_fl.getCellData(row, 'idx'), ds_fl.getCellData(row, 'wt'), ds_fl.getCellData(row, 'onDt'));

    let dmCoshippingNo = ds_fl.getCellData(row, 'dmCoshippingNo');

    let iTotalRows = 0;

    for (let i = 0; i < ds_fl.getRowCount(); i++) {
        let coshippingFlag = false;

        if (ds_fl.getCellData(i, 'dmCoshippingNo') != "") {
            for (let j = 0; j < ds_fl.getRowCount(); j++) {
                if (i != j && ds_fl.getCellData(i, 'dmCoshippingNo') == ds_fl.getCellData(j, 'dmCoshippingNo')) {
                    coshippingFlag = true;
                    break;
                }
            }

            if (!coshippingFlag) {
                iTotalRows = iTotalRows + 1;
            }
        } else {
            iTotalRows = iTotalRows + 1;
        }
    }
    scwin.iCargoCnt = iTotalRows;
    scwin.originText = "총 " + scwin.iCargoCnt + "건";
    scwin.f_SearchCar('cargo', row);
};

scwin.sbm_RetrieveBlk_submiterror = function(e) {
    if (e && e.errorCode != 50015) {
        $c.gus.cfShowError(e);
    }
};

