    if (ds_fl.getCellData(rowIndex, 'idx') != "") {
        let cond = "?CargoType=cargo&idx=" + ds_fl.getCellData(rowIndex, 'idx');
        let sUrl;
        if (ds_fl.getCellData(rowIndex, 'statuss') == '대기') {
            sUrl = "/ui/bp/fbp/op/ac/ez_202_01_01p.xml" + cond;
        } else {
            sUrl = "/ui/bp/fbp/op/ac/ez_202_01_01b.xml" + cond;
        }
        window.open(sUrl, 'fl', 'toolbar=no,location=no,status=no,menubar=no,scrollbars=no,resizable=no,width=980,height=800,top=0,left=0');
    }
};

